// // This module is designed to count down on each positive edge of the clock signal and set to maximum on a high reset signal.
module up_counter (
    input      clk,
    input      rst,
    output reg [3:0] count
);

always @(posedge clk or posedge rst) begin
    if (rst)
        count <= 4'b0000;
    else
        count <= count + 1'b1;
end

endmodule
